# generate_rate_card_changelog.py
# Compares two rate card YAML files and outputs a structured changelog.

import yaml

def diff_rate_cards(old_path: str, new_path: str) -> dict:
    with open(old_path) as f: old = yaml.safe_load(f)
    with open(new_path) as f: new = yaml.safe_load(f)

    changes = []
    old_prices = old.get("provider_prices", {})
    new_prices = new.get("provider_prices", {})

    for model in set(list(old_prices) + list(new_prices)):
        old_m = old_prices.get(model, {})
        new_m = new_prices.get(model, {})
        for token_type in set(list(old_m) + list(new_m)):
            old_val = old_m.get(token_type, 0.0)
            new_val = new_m.get(token_type, 0.0)
            if abs(old_val - new_val) > 0.0001:
                pct = (new_val - old_val) / old_val * 100 if old_val else 0
                changes.append({
                    "model": model,
                    "token_type": token_type,
                    "old_price_per_M": old_val,
                    "new_price_per_M": new_val,
                    "delta_pct": round(pct, 1),
                    "direction": "increase" if new_val > old_val else "decrease",
                })

    old_markup = old.get("markup_policy", {})
    new_markup = new.get("markup_policy", {})
    markup_changes = {}
    for key in set(list(old_markup) + list(new_markup)):
        if old_markup.get(key) != new_markup.get(key):
            markup_changes[key] = {
                "old": old_markup.get(key),
                "new": new_markup.get(key),
            }

    return {
        "from_version": old.get("version", "unknown"),
        "to_version":   new.get("version", "unknown"),
        "effective_date": new.get("effective_date", ""),
        "price_changes": changes,
        "markup_changes": markup_changes,
        "net_direction": "increase" if sum(c["delta_pct"] for c in changes) > 0 else "decrease",
    }


def format_changelog_email(diff: dict) -> str:
    lines = [
        f"Rate Card Update: {diff['from_version']} -> {diff['to_version']}",
        f"Effective: {diff['effective_date']}",
        "",
        "Price changes:",
    ]
    for c in sorted(diff["price_changes"], key=lambda x: abs(x["delta_pct"]), reverse=True):
        arrow = "+" if c["direction"] == "increase" else "-"
        lines.append(
            f"  {c['model']} {c['token_type']}: "
            f"${c['old_price_per_M']}/M -> ${c['new_price_per_M']}/M "
            f"({arrow}{abs(c['delta_pct']):.1f}%)"
        )
    if diff["markup_changes"]:
        lines.append("\nMarkup policy changes:")
        for k, v in diff["markup_changes"].items():
            lines.append(f"  {k}: {v['old']} -> {v['new']}")
    return "\n".join(lines)

# rate_card_change_tracking.py
# Track whether teams have acknowledged the rate card change.

import datetime
import json

def load_acknowledgment_tracker(path: str) -> dict:
    try:
        with open(path) as f:
            return json.load(f)
    except FileNotFoundError:
        return {}

def record_acknowledgment(
    tracker: dict,
    team_id: str,
    acknowledged_by: str,
    method: str,  # "email_reply" | "portal_click" | "meeting"
) -> None:
    tracker[team_id] = {
        "acknowledged_by": acknowledged_by,
        "method": method,
        "timestamp": datetime.datetime.utcnow().isoformat(),
    }

def get_non_responders(
    all_teams: list[str],
    tracker: dict,
    days_since_announcement: int,
) -> list[str]:
    """Return teams that have not acknowledged after N days."""
    unacked = [t for t in all_teams if t not in tracker]
    if days_since_announcement >= 14:
        # Two weeks in: escalate unacknowledged teams to their engineering manager
        print(f"[ESCALATE] {len(unacked)} teams have not acknowledged the rate card update:")
        for t in unacked:
            print(f"  - {t}")
    return unacked
